import SwiftUI
import EventKit

// REQUIRES PLIST: NSRemindersUsageDescription
class RemindersViewModel: ObservableObject {
    private let store = EKEventStore()
    @Published var isAuthorized = false
    @Published var lastAddedTitle: String?
    @Published var errorMessage: String?

    func requestAccess() {
        store.requestAccess(to: .reminder) { [weak self] granted, _ in
            DispatchQueue.main.async {
                guard let self = self else { return }
                if granted {
                    self.isAuthorized = true
                    self.errorMessage = nil
                } else {
                    self.isAuthorized = false
                    self.errorMessage = "Reminders access denied"
                }
            }
        }
    }

    func addReminder(title: String) {
        guard !title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return }
        guard let calendar = store.defaultCalendar(for: .reminder) else {
            DispatchQueue.main.async { self.errorMessage = "No reminder calendar" }
            return
        }
        let reminder = EKReminder(eventStore: store)
        reminder.calendar = calendar
        reminder.title = title
        do {
            try store.save(reminder, commit: true)
            DispatchQueue.main.async {
                self.lastAddedTitle = title
                self.errorMessage = nil
            }
        } catch {
            DispatchQueue.main.async { self.errorMessage = error.localizedDescription }
        }
    }
}

struct RemindersView: View {
    @StateObject private var viewModel = RemindersViewModel()
    @State private var title = ""

    var body: some View {
        VStack(spacing: 16) {
            TextField("Reminder title", text: $title)
                .textFieldStyle(.roundedBorder)
                .disabled(!viewModel.isAuthorized)
            Button("Add Reminder") { viewModel.addReminder(title: title) }
                .disabled(!viewModel.isAuthorized)
            if let message = viewModel.errorMessage {
                Text(message).foregroundStyle(.red)
            }
            if let added = viewModel.lastAddedTitle {
                Text("Added: " + added).foregroundStyle(.secondary)
            }
        }
        .onAppear { viewModel.requestAccess() }
    }
}
